+  private getCursorOrder(orderBy?: CrudOptions['orderBy']) {
+    if (!orderBy) {
+      return [] as { field: string; direction: 'asc' | 'desc' }[];
+    }
+
+    const entries = (Array.isArray(orderBy) ? orderBy : [orderBy]).flatMap(
+      (part) => Object.entries(part as Record<string, unknown>),
+    );
+    const order = entries.map(([field, direction]) => {
+      const normalizedDirection = String(direction).toLowerCase();
+      if (normalizedDirection !== 'asc' && normalizedDirection !== 'desc') {
+        throw new BadRequestException(
+          'cursor pagination supports only asc and desc orderBy directions',
+        );
+      }
+      return { field, direction: normalizedDirection as 'asc' | 'desc' };
+    });
+    const idField = this.crudConfig.id_field as string;
+    if (!order.some(({ field }) => field === idField)) {
+      order.push({ field: idField, direction: 'asc' });
+    }
+    return order;
+  }
+
+  private toOrderBy(order: { field: string; direction: 'asc' | 'desc' }[]) {
+    return order.map(({ field, direction }) => ({ [field]: direction }));
+  }
+
+  private decodeCursor(
+    cursor: string,
+    order: { field: string; direction: 'asc' | 'desc' }[],
+  ): Record<string, any> {
+    let values: Record<string, any>;
+    try {
+      const decoded = Buffer.from(cursor, 'base64').toString('utf8');
+      values = JSON.parse(decoded);
+    } catch {
+      throw new BadRequestException('cursor must be valid Base64 JSON');
+    }
+
+    if (!values || Array.isArray(values) || typeof values !== 'object') {
+      throw new BadRequestException('cursor must be valid Base64 JSON');
+    }
+    const sort = order
+      .map(({ field, direction }) => `${field}:${direction}`)
+      .join(',');
+    if (values.__sort !== sort) {
+      throw new BadRequestException('cursor orderBy does not match request');
+    }
+    const idField = this.crudConfig.id_field as string;
+    if (!Object.prototype.hasOwnProperty.call(values, idField)) {
+      throw new BadRequestException('cursor is missing the entity ID');
+    }
+    for (const { field } of order) {
+      if (!Object.prototype.hasOwnProperty.call(values, field)) {
+        throw new BadRequestException(`cursor is missing sort field ${field}`);
+      }
+    }
+    return values;
+  }
